                  setForm((f) => ({ ...f, system: e.target.value as ConversationSystem }))
                }
              >
                <option value="Claude">Claude</option>
                <option value="ChatGPT">ChatGPT</option>
                <option value="Other">Other</option>
              </select>
            </div>
            <div style={{ flex: 1 }}>
              <label style={LABEL_STYLE}>Role</label>
              <select
                style={SELECT_STYLE}
                value={form.role}
                onChange={(e) =>
                  setForm((f) => ({ ...f, role: e.target.value as ConversationRole }))
                }
              >
                {(Object.keys(ROLE_LABELS) as ConversationRole[]).map((r) => (
                  <option key={r} value={r}>
                    {ROLE_LABELS[r]}
                  </option>
                ))}
              </select>
            </div>
          </div>
          <div style={FIELD_STYLE}>
            <label style={LABEL_STYLE}>Notes</label>
            <textarea
              style={TEXTAREA_STYLE}
              placeholder="Optional notes..."
              value={form.notes}
              onChange={(e) => setForm((f) => ({ ...f, notes: e.target.value }))}
            />
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "12px" }}>
            <input
              id={`auth-add-${scopeId}`}
              type="checkbox"
              checked={form.authoritative}
              onChange={(e) => setForm((f) => ({ ...f, authoritative: e.target.checked }))}
            />
            <label htmlFor={`auth-add-${scopeId}`} style={{ fontSize: "13px", color: "#374151" }}>
              Authoritative source
            </label>
          </div>
          <div style={{ display: "flex", gap: "8px" }}>
            <button
              onClick={handleAdd}
              disabled={!form.url.trim()}
              style={{
                padding: "6px 14px",
                background: form.url.trim() ? "#2563eb" : "#93c5fd",
                color: "#fff",
                border: "none",
                borderRadius: "6px",
                fontSize: "13px",
                fontWeight: 600,
                cursor: form.url.trim() ? "pointer" : "not-allowed",
              }}
            >
              Add Reference
            </button>
            <button
              onClick={() => {
                setForm({ ...emptyForm });
                setShowForm(false);
              }}
              style={{
                padding: "6px 14px",
                background: "#f3f4f6",
                color: "#374151",
                border: "1px solid #d1d5db",
                borderRadius: "6px",
                fontSize: "13px",
                cursor: "pointer",
              }}
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {references.length === 0 && !showForm && (
        <div style={{ fontSize: "13px", color: "#9ca3af", padding: "8px 0" }}>
          No conversation references yet.
        </div>
      )}

      {references.map((r) => (
        <RefRow key={r.id} conversationRef={r} onUpdate={onUpdate} onDelete={onDelete} />
      ))}
    </div>
  );
}

